('spanish:p-1-spanish-sounds-and-the-alphabet:tf:82bc0fdb', 'spanish', 'spanish:p-1-spanish-sounds-and-the-alphabet', 'P.1 Spanish Sounds and the Alphabet', 'tf', 'tf', 1, '{"question": "Words ending in ‑r stress the second-to-last syllable."}'::jsonb, '{"answer": false, "explain": "Ending in a consonant (not n/s) → stress the LAST syllable (ha-BLAR)."}'::jsonb),
('spanish:p-1-spanish-sounds-and-the-alphabet:learn:335c50c7', 'spanish', 'spanish:p-1-spanish-sounds-and-the-alphabet', 'P.1 Spanish Sounds and the Alphabet', 'learn', 'mcq', 1, '{"readingTitle": "The five vowel sounds — short, pure, always the same", "reading": "<p>Spanish has <strong>five</strong> vowel sounds and they <strong>never change</strong> — unlike English. Each is short and crisp. Tap 🔊 to hear them.</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"a\">a</span> — like ‘cat’</td><td><span data-say=\"alto\">alto</span>, <span data-say=\"antes\">antes</span></td></tr>\n              <tr><td><span data-say=\"e\">e</span> — like ‘pet’</td><td><span data-say=\"español\">español</span>, <span data-say=\"medio\">medio</span></td></tr>\n              <tr><td><span data-say=\"i\">i</span> — like ‘see’</td><td><span data-say=\"idea\">idea</span>, <span data-say=\"iglesia\">iglesia</span></td></tr>\n              <tr><td><span data-say=\"o\">o</span> — like ‘hot’</td><td><span data-say=\"dos\">dos</span>, <span data-say=\"cinco\">cinco</span></td></tr>\n              <tr><td><span data-say=\"u\">u</span> — like ‘boot’</td><td><span data-say=\"universidad\">universidad</span>, <span data-say=\"instituto\">instituto</span></td></tr>\n            </table>\n            <p>Never let a vowel ‘glide’ the way English does — keep it pure and even.</p>", "question": "How many vowel sounds does Spanish have, and do they change?", "options": ["Five, and they stay the same", "Twelve different ones, like in English", "Five, but they glide", "Three main ones only"]}'::jsonb, '{"answer": 0, "explain": "Five pure vowels (a, e, i, o, u) that never change — the foundation of clear Spanish."}'::jsonb),
('spanish:p-1-spanish-sounds-and-the-alphabet:learn:d30b33b5', 'spanish', 'spanish:p-1-spanish-sounds-and-the-alphabet', 'P.1 Spanish Sounds and the Alphabet', 'learn', 'mcq', 1, '{"readingTitle": "The alphabet and the extra letter ñ", "reading": "<p>The Spanish alphabet is the same as English plus one extra letter: <strong>ñ</strong> (‘eñe’). Some useful letter names: <span data-say=\"be\">be</span> (b), <span data-say=\"ce\">ce</span> (c), <span data-say=\"jota\">jota</span> (j), <span data-say=\"hache\">hache</span> (h), <span data-say=\"uve\">uve</span> (v), <span data-say=\"i griega\">i griega</span> (y).</p>\n            <ul>\n              <li><strong>ñ</strong> = the ‘ny’ sound in ‘onion’: <span data-say=\"mañana\">mañana</span>, <span data-say=\"cumpleaños\">cumpleaños</span>.</li>\n              <li>Spelling aloud matters for the exam — practise spelling your name and town.</li>\n            </ul>", "question": "Which letter is unique to the Spanish alphabet?", "options": ["ñ", "k", "w", "q"]}'::jsonb, '{"answer": 0, "explain": "ñ (eñe) is the extra letter; it makes the ‘ny’ sound as in mañana."}'::jsonb),
('spanish:p-1-spanish-sounds-and-the-alphabet:learn:239be625', 'spanish', 'spanish:p-1-spanish-sounds-and-the-alphabet', 'P.1 Spanish Sounds and the Alphabet', 'learn', 'mcq', 1, '{"readingTitle": "Stress and the written accent (á é í ó ú)", "reading": "<p>Two simple rules tell you which syllable is stressed:</p>\n            <ul>\n              <li>Words ending in a <strong>vowel, n or s</strong> → stress the <strong>second-to-last</strong> syllable: <span data-say=\"hablo\">hablo</span>, <span data-say=\"joven\">joven</span>.</li>\n              <li>Words ending in any <strong>other consonant</strong> → stress the <strong>last</strong> syllable: <span data-say=\"hablar\">hablar</span>, <span data-say=\"ciudad\">ciudad</span>.</li>\n              <li>A <strong>written accent</strong> overrides both and shows the stress: <span data-say=\"región\">región</span>, <span data-say=\"sonreír\">sonreír</span>.</li>\n            </ul>\n            <p>Accents can change meaning: <span data-say=\"sí\">sí</span> (yes) vs <em>si</em> (if); <span data-say=\"él\">él</span> (he) vs <em>el</em> (the). The upside-down <strong>¿ ¡</strong> open questions and exclamations.</p>", "question": "‘hablar’ ends in ‑r. Which syllable is stressed?", "options": ["the last one (ha-blar)", "none of them — it needs a written accent", "the first one (ha-blar)", "the middle one"]}'::jsonb, '{"answer": 0, "explain": "Ending in a consonant other than n/s → stress the final syllable: ha-BLAR."}'::jsonb),
('spanish:p-1-spanish-sounds-and-the-alphabet:learn:e1b7d6b4', 'spanish', 'spanish:p-1-spanish-sounds-and-the-alphabet', 'P.1 Spanish Sounds and the Alphabet', 'learn', 'mcq', 1, '{"readingTitle": "The letter C: two sounds (+ Z and QU)", "reading": "<p>The letter <strong>c</strong> makes two different sounds depending on the next letter:</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><strong>ca, co, cu</strong> → hard /k/</td><td><span data-say=\"casa\">casa</span>, <span data-say=\"coche\">coche</span>, <span data-say=\"escuchar\">escuchar</span></td></tr>\n              <tr><td><strong>ce, ci</strong> → soft ‘th’ (Spain)</td><td><span data-say=\"cerca\">cerca</span>, <span data-say=\"cinco\">cinco</span></td></tr>\n            </table>\n            <ul>\n              <li><strong>z</strong> makes the same soft sound as ce/ci: <span data-say=\"zona\">zona</span>, <span data-say=\"manzana\">manzana</span>.</li>\n              <li>To get a hard /k/ before e or i, Spanish uses <strong>que, qui</strong> (the u is silent): <span data-say=\"porque\">porque</span>, <span data-say=\"quince\">quince</span>.</li>\n            </ul>", "question": "How is the ‘c’ in ‘cinco’ pronounced?", "options": ["soft (like ‘th’ / ‘s’)", "just like an English ‘ch’ sound", "hard, like ‘k’", "silent"]}'::jsonb, '{"answer": 0, "explain": "c before e or i is soft; before a/o/u it is hard /k/. So cinco = ‘thin-ko’."}'::jsonb),
('spanish:p-1-spanish-sounds-and-the-alphabet:learn:86462cbf', 'spanish', 'spanish:p-1-spanish-sounds-and-the-alphabet', 'P.1 Spanish Sounds and the Alphabet', 'learn', 'mcq', 1, '{"readingTitle": "The letter G, and GUE / GUI", "reading": "<p>Like c, the letter <strong>g</strong> makes two sounds:</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><strong>ga, go, gu</strong> → hard /g/</td><td><span data-say=\"gato\">gato</span>, <span data-say=\"largo\">largo</span>, <span data-say=\"preguntar\">preguntar</span></td></tr>\n              <tr><td><strong>ge, gi</strong> → throaty /x/ (like ‘loch’)</td><td><span data-say=\"gente\">gente</span>, <span data-say=\"gimnasio\">gimnasio</span></td></tr>\n            </table>\n            <ul>\n              <li>To keep a hard /g/ before e or i, add a silent <strong>u</strong>: <span data-say=\"hamburguesa\">hamburguesa</span>, <span data-say=\"guitarra\">guitarra</span>.</li>\n            </ul>", "question": "How is the ‘g’ in ‘gente’ pronounced?", "options": ["throaty, like the ‘ch’ in ‘loch’", "like an English ‘j’ as in the word ‘jam’ exactly", "hard, like ‘g’ in ‘go’", "silent"]}'::jsonb, '{"answer": 0, "explain": "g before e or i is the throaty /x/ sound; before a/o/u it is a hard /g/."}'::jsonb),
('spanish:p-1-spanish-sounds-and-the-alphabet:learn:2f294717', 'spanish', 'spanish:p-1-spanish-sounds-and-the-alphabet', 'P.1 Spanish Sounds and the Alphabet', 'learn', 'mcq', 1, '{"readingTitle": "Why sounds matter in the exam", "reading": "<p>Sound-Symbol Correspondences (SSCs) are tested directly:</p>\n            <ul>\n              <li><strong>Paper 2 (Speaking): Read-aloud</strong> — you read a short text out loud and are marked on accurate sounds.</li>\n              <li><strong>Paper 1 (Listening): Dictation</strong> — you write down what you hear, so you must link sound → spelling.</li>\n            </ul>\n            <p>Master a few rules (soft c, throaty g, silent h, rolled r) and both tasks become far easier. <span class=\"tier-h\">H</span> Higher texts are longer, but the same rules apply.</p>", "question": "Which TWO papers test your sound knowledge most directly?", "options": ["Speaking (read-aloud) and Listening (dictation)", "The Reading paper and the Writing paper only, nothing else", "Writing and Speaking essays", "None — sounds aren''t assessed"]}'::jsonb, '{"answer": 0, "explain": "Read-aloud (Paper 2) and dictation (Paper 1) both reward accurate sound-symbol links."}'::jsonb),
('spanish:p-1-spanish-sounds-and-the-alphabet:misc:89c311cf', 'spanish', 'spanish:p-1-spanish-sounds-and-the-alphabet', 'P.1 Spanish Sounds and the Alphabet', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Pronouncing ‘v’ (verde) like an English ‘v’.</p><p><strong>✅ The correct idea:</strong> Spanish v sounds almost like a soft ‘b’: verde.</p>", "question": "How is Spanish ‘v’ (verde) pronounced?", "options": ["almost like a soft ‘b’", "exactly like an English ‘v’", "like an English ‘f’", "it is always silent"]}'::jsonb, '{"answer": 0, "explain": "v and b sound almost identical in Spanish — a soft ‘b’."}'::jsonb),
('spanish:p-1-spanish-sounds-and-the-alphabet:misc:02aefbb0', 'spanish', 'spanish:p-1-spanish-sounds-and-the-alphabet', 'P.1 Spanish Sounds and the Alphabet', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Saying the ‘h’ in ‘hospital’.</p><p><strong>✅ The correct idea:</strong> The h is silent: ‘ospital’.</p>", "question": "How do you pronounce the h in ‘hospital’?", "options": ["you don''t — it is silent", "as a strong English ‘h’ sound", "as a throaty sound", "as a ‘j’"]}'::jsonb, '{"answer": 0, "explain": "h is silent in Spanish (hospital, hoy)."}'::jsonb),
('spanish:p-1-spanish-sounds-and-the-alphabet:misc:9d654ce6', 'spanish', 'spanish:p-1-spanish-sounds-and-the-alphabet', 'P.1 Spanish Sounds and the Alphabet', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Reading ‘gente’ with a hard English ‘g’.</p><p><strong>✅ The correct idea:</strong> g before e/i is throaty: ‘hente’.</p>", "question": "The g in ‘gente’ should sound…", "options": ["throaty, like ‘loch’", "like an English ‘j’ in ‘jam’", "hard, like ‘go’", "silent"]}'::jsonb, '{"answer": 0, "explain": "g before e/i is the throaty /x/, not a hard g."}'::jsonb),
('spanish:p-1-spanish-sounds-and-the-alphabet:misc:2b393711', 'spanish', 'spanish:p-1-spanish-sounds-and-the-alphabet', 'P.1 Spanish Sounds and the Alphabet', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Reading ‘ce’ in ‘cerca’ as a hard ‘k’.</p><p><strong>✅ The correct idea:</strong> c before e/i is soft: ‘therka’.</p>", "question": "The c in ‘cerca’ is…", "options": ["soft (‘th’/‘s’)", "hard, like ‘k’", "silent", "a throaty sound"]}'::jsonb, '{"answer": 0, "explain": "c before e/i is soft; only ca/co/cu are hard."}'::jsonb),
('spanish:p-1-spanish-sounds-and-the-alphabet:misc:f9f0709a', 'spanish', 'spanish:p-1-spanish-sounds-and-the-alphabet', 'P.1 Spanish Sounds and the Alphabet', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Letting vowels glide, e.g. ‘no’ → ‘nou’.</p><p><strong>✅ The correct idea:</strong> Keep vowels pure and short: ‘no’.</p>", "question": "How should you say a Spanish vowel like the ‘o’ in ‘no’?", "options": ["short and pure, no glide", "long, gliding towards an ‘ou’ sound", "silent unless stressed", "rolled"]}'::jsonb, '{"answer": 0, "explain": "Spanish vowels never glide — keep them crisp."}'::jsonb),
('spanish:p-1-spanish-sounds-and-the-alphabet:tips:064e3d84', 'spanish', 'spanish:p-1-spanish-sounds-and-the-alphabet', 'P.1 Spanish Sounds and the Alphabet', 'tips', 'mcq', 1, '{"readingTitle": "tip — Paper 2 — Read-aloud (speaking)", "reading": "Before you read, scan for the traps: soft c/z, throaty ge/gi, silent h, and the vowels. Read slowly and evenly — accurate sounds beat speed. Rolling the rr and keeping vowels pure make the biggest difference.", "question": "What matters most in the read-aloud task?", "options": ["accurate sounds, read steadily", "reading it as fast as you possibly can", "a loud English accent", "skipping the hard words"]}'::jsonb, '{"answer": 0, "explain": "You''re marked on accurate pronunciation, not speed."}'::jsonb),
('spanish:p-1-spanish-sounds-and-the-alphabet:tips:bdc61b91', 'spanish', 'spanish:p-1-spanish-sounds-and-the-alphabet', 'P.1 Spanish Sounds and the Alphabet', 'tips', 'mcq', 1, '{"readingTitle": "tip — Paper 1 — Dictation (listening)", "reading": "Link sound to spelling: a soft ‘th’ could be c (ce/ci) or z; a throaty sound is ge/gi or j; a silent h still gets written. Say the word in your head and picture the letters.", "question": "You hear a throaty sound before an ‘e’. It is most likely spelt…", "options": ["ge or j", "gue or gui", "ca", "qu"]}'::jsonb, '{"answer": 0, "explain": "The throaty /x/ before e is ge (or j); gue would be a hard g."}'::jsonb),
('spanish:p-1-spanish-sounds-and-the-alphabet:tips:32c8f2cd', 'spanish', 'spanish:p-1-spanish-sounds-and-the-alphabet', 'P.1 Spanish Sounds and the Alphabet', 'tips', 'mcq', 1, '{"readingTitle": "evaluate — Paper 4 — Accents in writing", "reading": "In written Spanish, missing or wrong accents can cost accuracy marks and even change meaning (sí/si, él/el). When you learn a word, learn its accent as part of the spelling.", "question": "Why do written accents matter in Paper 4?", "options": ["they affect accuracy and can change meaning", "they only ever matter when you are speaking aloud", "they are optional decoration", "they show the plural"]}'::jsonb, '{"answer": 0, "explain": "Accents carry meaning and accuracy marks (sí = yes vs si = if)."}'::jsonb),
('spanish:p-1-spanish-sounds-and-the-alphabet:fib:29720793', 'spanish', 'spanish:p-1-spanish-sounds-and-the-alphabet', 'P.1 Spanish Sounds and the Alphabet', 'fib', 'fib', 1, '{"question": "The word for ‘five’ is _____. <span data-say=\"cinco\" data-listen>cinco</span>", "blankOptions": {"B1": ["soft", "ñan", "throaty", "cinco"]}}'::jsonb, '{"blanks": {"B1": "cinco"}}'::jsonb),
